/**
 * Unit tests for src/hooks/src/lib/worktree-advisory.ts (#1794 PR-2)
 *
 * Covers writeWorktreeAdvisory and consumeWorktreeAdvisories — the deferred
 * delivery mechanism that bridges WorktreeCreate (no additionalContext
 * consumption) → next UserPromptSubmit (additionalContext consumed).
 */

import { describe, it, expect, beforeEach, afterEach } from 'vitest';
import { existsSync, mkdirSync, mkdtempSync, readdirSync, readFileSync, rmSync, writeFileSync } from 'node:fs';
import { join } from 'node:path';
import { tmpdir } from 'node:os';
import {
  writeWorktreeAdvisory,
  consumeWorktreeAdvisories,
  slugify,
} from '../lib/worktree-advisory.js';

describe('worktree-advisory (#1794 PR-2)', () => {
  let tmp: string;

  beforeEach(() => {
    tmp = mkdtempSync(join(tmpdir(), 'wt-adv-'));
  });

  afterEach(() => {
    try { rmSync(tmp, { recursive: true, force: true }); } catch { /* best-effort */ }
  });

  // -----------------------------------------------------------------------
  // slugify
  // -----------------------------------------------------------------------
  describe('slugify', () => {
    it('passes through ascii names unchanged', () => {
      expect(slugify('feature-auth')).toBe('feature-auth');
      expect(slugify('bold-oak-a3f2')).toBe('bold-oak-a3f2');
      expect(slugify('snake_case_ok')).toBe('snake_case_ok');
    });

    it('replaces unsafe characters with dashes', () => {
      expect(slugify('feat/foo')).toBe('feat-foo');
      expect(slugify('path with spaces')).toBe('path-with-spaces');
      expect(slugify('weird.name.dots')).toBe('weird-name-dots');
    });

    it('collapses consecutive dashes and trims edges', () => {
      expect(slugify('--abc--')).toBe('abc');
      expect(slugify('a//b//c')).toBe('a-b-c');
    });

    it('falls back to "unknown" for empty input', () => {
      expect(slugify('')).toBe('unknown');
      expect(slugify('!!!')).toBe('unknown');
    });

    it('does not start a hidden file', () => {
      // Important: slug must not produce a dotfile that hides advisories.
      expect(slugify('.hidden')).not.toMatch(/^\./);
      expect(slugify('-leading-dash')).not.toMatch(/^-/);
    });
  });

  // -----------------------------------------------------------------------
  // writeWorktreeAdvisory
  // -----------------------------------------------------------------------
  describe('writeWorktreeAdvisory', () => {
    it('creates .claude/state/ and writes the advisory file', () => {
      const ok = writeWorktreeAdvisory('Test advisory body', 'feature-x', tmp);
      expect(ok).toBe(true);
      const dir = join(tmp, '.claude', 'state');
      expect(existsSync(dir)).toBe(true);
      const files = readdirSync(dir);
      expect(files).toContain('worktree-advisory-feature-x.md');
      const content = readFileSync(join(dir, 'worktree-advisory-feature-x.md'), 'utf8');
      expect(content).toContain('Test advisory body');
      expect(content.endsWith('\n')).toBe(true);
    });

    it('returns false on empty/whitespace-only advisory', () => {
      expect(writeWorktreeAdvisory('', 'name', tmp)).toBe(false);
      expect(writeWorktreeAdvisory('   \n  ', 'name', tmp)).toBe(false);
      expect(existsSync(join(tmp, '.claude', 'state'))).toBe(false);
    });

    it('returns false on missing projectDir', () => {
      expect(writeWorktreeAdvisory('advisory', 'name', '')).toBe(false);
    });

    it('idempotent on repeated calls with same name (overwrites, no duplicate)', () => {
      writeWorktreeAdvisory('first', 'feat-x', tmp);
      writeWorktreeAdvisory('second', 'feat-x', tmp);
      const files = readdirSync(join(tmp, '.claude', 'state'));
      expect(files.filter((f: string) => f.includes('feat-x'))).toHaveLength(1);
      const content = readFileSync(join(tmp, '.claude', 'state', 'worktree-advisory-feat-x.md'), 'utf8');
      expect(content).toContain('second');
      expect(content).not.toContain('first');
    });

    it('sanitizes unsafe characters in worktree name before writing', () => {
      writeWorktreeAdvisory('advisory', 'feat/with/slash', tmp);
      const files = readdirSync(join(tmp, '.claude', 'state'));
      expect(files).toContain('worktree-advisory-feat-with-slash.md');
    });

    it('returns false (does not throw) when the write target is unwritable', () => {
      // Pass a path that contains a null byte — node:fs throws on this
      const result = writeWorktreeAdvisory('advisory', 'name', '/no/such/path/\0bad');
      expect(result).toBe(false);
    });
  });

  // -----------------------------------------------------------------------
  // consumeWorktreeAdvisories
  // -----------------------------------------------------------------------
  describe('consumeWorktreeAdvisories', () => {
    it('returns null when no .claude/state/ exists', () => {
      expect(consumeWorktreeAdvisories(tmp)).toBeNull();
    });

    it('returns null when .claude/state/ exists but has no advisory files', () => {
      const stateDir = join(tmp, '.claude', 'state');
      mkdirSync(stateDir, { recursive: true });
      writeFileSync(join(stateDir, 'session.json'), '{}');
      expect(consumeWorktreeAdvisories(tmp)).toBeNull();
    });

    it('returns null on empty projectDir', () => {
      expect(consumeWorktreeAdvisories('')).toBeNull();
    });

    it('reads a single advisory and deletes the file', () => {
      writeWorktreeAdvisory('advisory body', 'feat-y', tmp);
      const content = consumeWorktreeAdvisories(tmp);
      expect(content).toBe('advisory body');
      // File deleted after consume — second call returns null
      expect(consumeWorktreeAdvisories(tmp)).toBeNull();
    });

    it('concatenates multiple advisories with a blank-line separator', () => {
      writeWorktreeAdvisory('advisory A', 'feat-a', tmp);
      writeWorktreeAdvisory('advisory B', 'feat-b', tmp);
      const content = consumeWorktreeAdvisories(tmp);
      expect(content).toContain('advisory A');
      expect(content).toContain('advisory B');
      expect(content).toContain('\n\n---\n\n');  // separator
    });

    it('consumes in sorted order (deterministic for multi-advisory output)', () => {
      writeWorktreeAdvisory('Z is later', 'zeta', tmp);
      writeWorktreeAdvisory('A is first', 'alpha', tmp);
      const content = consumeWorktreeAdvisories(tmp) as string;
      const idxA = content.indexOf('A is first');
      const idxZ = content.indexOf('Z is later');
      expect(idxA).toBeGreaterThan(-1);
      expect(idxZ).toBeGreaterThan(idxA);
    });

    it('ignores non-advisory files in .claude/state/', () => {
      writeWorktreeAdvisory('only one', 'real', tmp);
      const stateDir = join(tmp, '.claude', 'state');
      writeFileSync(join(stateDir, 'session-state.json'), '{}');
      writeFileSync(join(stateDir, 'goal-history.jsonl'), '{}\n');
      const content = consumeWorktreeAdvisories(tmp);
      expect(content).toBe('only one');
      // Non-advisory files survived
      expect(existsSync(join(stateDir, 'session-state.json'))).toBe(true);
      expect(existsSync(join(stateDir, 'goal-history.jsonl'))).toBe(true);
    });

    it('returns null if all advisory files are empty (whitespace-only content)', () => {
      // Manually write an empty advisory file (bypass write fn's empty guard)
      const stateDir = join(tmp, '.claude', 'state');
      mkdirSync(stateDir, { recursive: true });
      writeFileSync(join(stateDir, 'worktree-advisory-empty.md'), '   \n  \n');
      const content = consumeWorktreeAdvisories(tmp);
      expect(content).toBeNull();
      // Empty file STILL gets deleted (so we don't loop on it)
      expect(existsSync(join(stateDir, 'worktree-advisory-empty.md'))).toBe(false);
    });

    it('is idempotent — second call returns null', () => {
      writeWorktreeAdvisory('once', 'name', tmp);
      consumeWorktreeAdvisories(tmp);
      expect(consumeWorktreeAdvisories(tmp)).toBeNull();
    });

    it('does not throw on permission errors (best-effort delete)', () => {
      writeWorktreeAdvisory('content', 'one', tmp);
      // Even if unlink failed, the read still succeeded — function should not throw
      expect(() => consumeWorktreeAdvisories(tmp)).not.toThrow();
    });
  });

  // -----------------------------------------------------------------------
  // Round-trip: write → consume → empty
  // -----------------------------------------------------------------------
  describe('round-trip', () => {
    it('write + consume returns the exact body, then state is clean', () => {
      const body = 'Monorepo detected — consider sparsePaths.';
      writeWorktreeAdvisory(body, 'wt-abc', tmp);
      expect(consumeWorktreeAdvisories(tmp)).toBe(body);
      expect(consumeWorktreeAdvisories(tmp)).toBeNull();
    });
  });
});
